import { useState, useMemo } from "react";
import { Loader2, User, Bot, Wrench, ChevronDown, ChevronRight } from "lucide-react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { useTranscriptQuery } from "../../hooks/use-tauri-query";
import type { CheckpointSummary } from "../../lib/ipc";

interface TranscriptViewProps {
  repoPath: string;
  checkpoint: CheckpointSummary | null;
}

function isJsonString(text: string): boolean {
  const trimmed = text.trim();
  if (
    (trimmed.startsWith("{") && trimmed.endsWith("}")) ||
    (trimmed.startsWith("[") && trimmed.endsWith("]"))
  ) {
    try {
      JSON.parse(trimmed);
      return true;
    } catch {
      return false;
    }
  }
  return false;
}

/** Tokenize JSON string into colored spans using React elements */
function JsonHighlight({ json }: { json: string }) {
  const tokens: React.ReactNode[] = [];
  const regex = /("(?:\\.|[^"\\])*")|(true|false|null)|(-?\d+(?:\.\d+)?(?:[eE][+-]?\d+)?)|([{}[\]:,])|(\s+)/g;
  let match: RegExpExecArray | null;
  let lastIndex = 0;
  let keyIndex = 0;

  const jsonStr = json;
  while ((match = regex.exec(jsonStr)) !== null) {
    if (match.index > lastIndex) {
      tokens.push(jsonStr.slice(lastIndex, match.index));
    }
    const [, str, bool, num, punct, ws] = match;
    if (str) {
      const after = jsonStr.slice(regex.lastIndex).match(/^\s*:/);
      if (after) {
        tokens.push(<span key={keyIndex++} className="text-blue">{str}</span>);
      } else {
        tokens.push(<span key={keyIndex++} className="text-green">{str}</span>);
      }
    } else if (bool) {
      tokens.push(<span key={keyIndex++} className="text-yellow">{bool}</span>);
    } else if (num) {
      tokens.push(<span key={keyIndex++} className="text-accent-fg">{num}</span>);
    } else if (punct) {
      tokens.push(<span key={keyIndex++} className="text-fg-subtle">{punct}</span>);
    } else if (ws) {
      tokens.push(ws);
    }
    lastIndex = regex.lastIndex;
  }
  if (lastIndex < jsonStr.length) {
    tokens.push(jsonStr.slice(lastIndex));
  }

  return <>{tokens}</>;
}

function JsonViewer({ text }: { text: string }) {
  const formatted = useMemo(() => {
    try {
      return JSON.stringify(JSON.parse(text.trim()), null, 2);
    } catch {
      return text;
    }
  }, [text]);

  const lines = formatted.split("\n");
  const [collapsed, setCollapsed] = useState(lines.length > 12);
  const preview = lines.slice(0, 6).join("\n");

  return (
    <div className="relative">
      <pre className="overflow-x-auto whitespace-pre-wrap font-mono text-xs leading-relaxed">
        {collapsed ? (
          <>
            <JsonHighlight json={preview} />
            {lines.length > 6 && (
              <span className="text-fg-faint">{"\n  ..."}</span>
            )}
          </>
        ) : (
          <JsonHighlight json={formatted} />
        )}
      </pre>
      {lines.length > 12 && (
        <button
          onClick={() => setCollapsed(!collapsed)}
          className="mt-1 flex items-center gap-1 text-[10px] text-accent-fg hover:text-accent"
        >
          {collapsed ? <ChevronRight size={10} /> : <ChevronDown size={10} />}
          {collapsed ? `Show all (${lines.length} lines)` : "Collapse"}
        </button>
      )}
    </div>
  );
}

function MarkdownContent({ content }: { content: string }) {
  return (
    <div className="prose-transcript">
      <ReactMarkdown remarkPlugins={[remarkGfm]}>{content}</ReactMarkdown>
    </div>
  );
}

function MessageContent({ content, toolInput }: { content: string; toolInput: string | null }) {
  if (toolInput) {
    if (isJsonString(toolInput)) {
      return <JsonViewer text={toolInput} />;
    }
    return (
      <pre className="overflow-x-auto whitespace-pre-wrap font-mono text-xs text-fg-subtle">
        {toolInput}
      </pre>
    );
  }

  if (isJsonString(content)) {
    return <JsonViewer text={content} />;
  }

  return <MarkdownContent content={content} />;
}

export function TranscriptView({ repoPath, checkpoint }: TranscriptViewProps) {
  const {
    data: messages,
    isLoading,
    error,
  } = useTranscriptQuery(
    repoPath,
    checkpoint?.checkpoint_id ?? "",
    0 // First session
  );

  if (!checkpoint) {
    return (
      <div className="flex items-center justify-center p-20 text-fg-subtle">
        Select a checkpoint to view its transcript
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="flex items-center justify-center p-20">
        <Loader2 size={20} className="animate-spin text-fg-subtle" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-8">
        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
          <p className="text-sm text-fg-muted">
            Transcript not available for this checkpoint
          </p>
          <p className="mt-1 text-xs text-fg-subtle">
            {error instanceof Error ? error.message : "Unknown error"}
          </p>
        </div>
      </div>
    );
  }

  if (!messages || messages.length === 0) {
    return (
      <div className="p-8">
        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
          <p className="text-sm text-fg-muted">No transcript data</p>
          <p className="mt-1 text-xs text-fg-subtle">
            This checkpoint may not have session data recorded
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="px-5 py-4">
      {/* Checkpoint header */}
      <div className="mb-4 rounded-lg border border-border-subtle bg-bg-overlay p-4">
        <h3 className="text-sm font-medium text-fg">
          {checkpoint.commit_message || checkpoint.checkpoint_id}
        </h3>
        <div className="mt-1 flex gap-3 text-xs text-fg-muted">
          <span className="font-mono">{checkpoint.commit_sha?.slice(0, 7) || checkpoint.checkpoint_id.slice(0, 7)}</span>
          <span>{checkpoint.files_touched.length} files</span>
          {checkpoint.sessions[0] && (
            <span>{checkpoint.sessions[0].agent}</span>
          )}
        </div>
      </div>

      {/* Messages */}
      <div className="space-y-3">
        {messages.map((msg, i) => (
          <div key={i} className="flex gap-3">
            {/* Role icon */}
            <div
              className={`flex h-7 w-7 shrink-0 items-center justify-center rounded-full ${
                msg.role === "user"
                  ? "bg-blue-bg text-blue"
                  : msg.role === "assistant"
                    ? "bg-accent-bg text-accent-fg"
                    : "bg-bg-hover text-fg-subtle"
              }`}
            >
              {msg.role === "user" ? (
                <User size={14} />
              ) : msg.role === "tool" ? (
                <Wrench size={14} />
              ) : (
                <Bot size={14} />
              )}
            </div>

            {/* Message content */}
            <div className="min-w-0 flex-1">
              <div className="mb-0.5 text-[10px] font-medium uppercase tracking-wider text-fg-subtle">
                {msg.role}
                {msg.tool_name && (
                  <span className="ml-2 normal-case tracking-normal text-blue">
                    {msg.tool_name}
                  </span>
                )}
              </div>
              <div className="rounded-lg border border-border-subtle bg-bg-overlay p-3 text-[13px] leading-relaxed text-fg-muted">
                <MessageContent content={msg.content} toolInput={msg.tool_input} />
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

